from typing import List, Dict, Tuple, Optional
from collections import deque


def topological_sort(n: int, edges: List[Tuple[int, int]]) -> Optional[List[int]]:
    adj: Dict[int, List[int]] = {i: [] for i in range(n)}
    in_degree = [0] * n

    for u, v in edges:
        adj[u].append(v)
        in_degree[v] += 1

    queue = deque([i for i in range(n) if in_degree[i] == 0])
    result = []

    while queue:
        u = queue.popleft()
        result.append(u)
        for v in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)

    if len(result) != n:
        return None
    return result

from typing import List


def search_rotated(nums: List[int], target: int) -> int:
    if not nums:
        return -1

    left, right = 0, len(nums) - 1

    while left <= right:
        mid = left + (right - left) // 2

        if nums[mid] == target:
            return mid

        # Left half is sorted
        if nums[left] <= nums[mid]:
            if nums[left] <= target < nums[mid]:
                right = mid - 1
            else:
                left = mid + 1
        # Right half is sorted
        else:
            if nums[mid] < target <= nums[right]:
                left = mid + 1
            else:
                right = mid - 1

    return -1

from typing import List, Tuple
from collections import deque


def shortest_path_in_maze(
    maze: List[List[int]],
    start: Tuple[int, int],
    end: Tuple[int, int]
) -> List[Tuple[int, int]]:
    if not maze or not maze[0]:
        return []
    rows, cols = len(maze), len(maze[0])

    if maze[start[0]][start[1]] == 1 or maze[end[0]][end[1]] == 1:
        return []

    if start == end:
        return [start]

    queue = deque([start])
    visited = {start}
    parent: Dict[Tuple[int, int], Tuple[int, int]] = {start: None}  # type: ignore

    while queue:
        r, c = queue.popleft()

        if (r, c) == end:
            path = []
            curr: Tuple[int, int] = (r, c)
            while curr is not None:
                path.append(curr)
                curr = parent[curr]
            return path[::-1]

        for dr, dc in [(-1, 0), (1, 0), (0, -1), (0, 1)]:
            nr, nc = r + dr, c + dc
            neighbor = (nr, nc)
            if 0 <= nr < rows and 0 <= nc < cols and maze[nr][nc] == 0 and neighbor not in visited:
                visited.add(neighbor)
                parent[neighbor] = (r, c)
                queue.append(neighbor)

    return []

