def remove_keys_with_value(d, value):
    """Remove all keys from dict `d` whose value equals `value`.
    >>> d = {'a': 1, 'b': 2, 'c': 1, 'd': 3}
    >>> remove_keys_with_value(d, 1)
    >>> d
    {'b': 2, 'd': 3}
    """
    for key in list(d):
        if d[key] == value:
            del d[key]
    return d

def fibonacci(n):
    """Return the nth Fibonacci number.
    fibonacci(0) -> 0
    fibonacci(1) -> 1
    fibonacci(6) -> 8
    """
    if n <= 1:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

